const startMs = $('Start Timer').first().json.startMs;
const checks = [];
let allPassed = true;

try {
  const r = $('Check User Service').first().json;
  const ok = !!(r?.status === 'ok' || r?.status === 'healthy' || r?.uptime);
  if (!ok) allPassed = false;
  checks.push({ name: 'user-service', ok, detail: r?.status ?? JSON.stringify(r).slice(0, 100) });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'user-service', ok: false, detail: e.message });
}

try {
  const r = $('Check PT Listing').first().json;
  // PT listing endpoint is public — expects array or { data: array }
  const arr = Array.isArray(r) ? r : (Array.isArray(r?.data) ? r.data : null);
  const ok = arr !== null;
  if (!ok) allPassed = false;
  const ptCount = ok ? arr.length : 0;
  checks.push({ name: 'pt-listing', ok, detail: ok ? `${ptCount} PT(s) listed` : (r?.error ?? 'unexpected shape') });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'pt-listing', ok: false, detail: e.message });
}

const durationMs = Date.now() - startMs;
return [{ json: {
  passed: allPassed,
  step: 'PT Review',
  statusCode: allPassed ? 200 : 503,
  details: checks.map(c => `${c.name}: ${c.ok ? 'OK' : 'FAIL'}`).join(' | '),
  durationMs,
  checks
} }];
